#!/bin/sh
# 1. Install Docker
apt-get update
apt-get install -y docker.io docker-compose git

# 2. Setup
mkdir -p /root/browserai/data
mkdir -p /root/browserai/bridge_config
cd /root/browserai

# 3. Docker compose
cat <<EOC > docker-compose.yml
services:
  browserai:
    image: node:20-bookworm
    container_name: browserai
    restart: always
    ports:
      - "8787:8787"
    environment:
      - PORT=8787
      - NODE_ENV=production
      - AUTH_SECRET=3eb892f1280bb68bae21012166c639851debe32ae460c890c2a766110068d34e
      - BROWSERAI_DB=/data/browserai.db
      - WORKSPACE_ROOT=/data/workspace
      - ARENA_AUTH_COOKIE=base64-
      - ARENA_ANON_KEY=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InRha2VjaGFyZ2UiLCJyb2xlIjoiYW5vbiIsImlhdCI6MTY4MDAwMDAwMCwiZXhwIjoxOTk1NzYwMDAwfQ.8RhjC9S7xYZw8L3fXr9kQ2tZ5mLn7PqX
      - BRIDGE_CONFIG_PATH=/bridge_config/config.json
    volumes:
      - ./data:/data
      - ./bridge_config:/bridge_config
    command: >
      sh -c "git clone https://github.com/robesthud/browserAI.git /app && 
             cd /app && 
             npm install && 
             npm run build && 
             npm start"
    working_dir: /app

  bridge:
    image: python:3.10
    container_name: lmarena-bridge
    restart: always
    ports:
      - "8000:8000"
    volumes:
      - ./bridge_config:/app/config_dir
    environment:
      - CONFIG_FILE=/app/config_dir/config.json
      - MODELS_FILE=/app/config_dir/models.json
    command: >
      sh -c "apt-get update && apt-get install -y git libgtk-3-0 libasound2 libnss3 libx11-xcb1 libxcomposite1 libxcursor1 libxdamage1 libxext6 libxfixes3 libxi6 libxrender1 libxtst6 libglib2.0-0 libpango-1-0-0 libpangocairo-1.0-0 libstdc++6 libgcc-s1 libc6 libdbus-1-3 libxcb1 libxkbcommon0 libgbm1 libatk1.0-0 libatk-bridge2.0-0 libcups2 libdrm2 libxt6 libdbus-glib-1-2 libpci3 libegl1 libopus0 libevent-2.1-7 ca-certificates &&
             git clone https://github.com/CloudWaddie/LMArenaBridge.git /app && 
             cd /app && 
             pip install -r requirements.txt && 
             playwright install firefox &&
             playwright install-deps firefox &&
             python3 -m src.main"
    working_dir: /app
EOC

# 4. Initialize config.json
echo '{"auth_tokens": ["base64-"]}' > bridge_config/config.json

# 5. Start
docker-compose up -d
